import { createRouter, createWebHistory } from 'vue-router'
import Home from './views/Home.vue'
import About from './views/About.vue'
import Contact from './views/Contact.vue'
import Careers from './views/Careers.vue'
import Login from './views/Login.vue'
import Register from './views/Register.vue'
import Dashboard from './views/Dashboard.vue'
import AdminDashboard from './views/AdminDashboard.vue'
import Learning from './views/Learning.vue'
import Exams from './views/Exams.vue'
import Subjects from './views/Subjects.vue'
import Progress from './views/Progress.vue'
import Notes from './views/Notes.vue'
import Schedule from './views/Schedule.vue'
import AITutor from './views/AITutor.vue'
import Profile from './views/Profile.vue'
import { checkRole } from './api/Auth.js'

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home
  },
  {
    path: '/about',
    name: 'About',
    component: About
  },
  {
    path: '/careers',
    name: 'Careers',
    component: Careers
  },
  {
    path: '/contact',
    name: 'Contact',
    component: Contact
  },
  {
    path: '/login',
    name: 'Login',
    component: Login
  },
  {
    path: '/register',
    name: 'Register',
    component: Register
  },
  {
    path: '/dashboard',
    name: 'Dashboard',
    component: Dashboard,
    meta: { requiresAuth: true }
  },
  {
    path: '/learning',
    name: 'Learning',
    component: Learning,
    meta: { requiresAuth: true }
  },
  {
    path: '/exams',
    name: 'Exams',
    component: Exams,
    meta: { requiresAuth: true }
  },
  {
    path: '/subjects',
    name: 'Subjects',
    component: Subjects,
    meta: { requiresAuth: true }
  },
  {
    path: '/subjects/:id',
    name: 'SubjectDetail',
    component: Subjects,
    meta: { requiresAuth: true }
  },
  {
    path: '/progress',
    name: 'Progress',
    component: Progress,
    meta: { requiresAuth: true }
  },
  {
    path: '/notes',
    name: 'Notes',
    component: Notes,
    meta: { requiresAuth: true }
  },
  {
    path: '/schedule',
    name: 'Schedule',
    component: Schedule,
    meta: { requiresAuth: true }
  },
  {
    path: '/ai-tutor',
    name: 'AITutor',
    component: AITutor,
    meta: { requiresAuth: true }
  },
  {
    path: '/profile',
    name: 'Profile',
    component: Profile,
    meta: { requiresAuth: true }
  },
  {
    path: '/admin',
    name: 'AdminDashboard',
    component: AdminDashboard,
    meta: { requiresAuth: true, requiresAdmin: true }
  }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

// Navigation guard for authentication and role-based access
router.beforeEach(async (to, from, next) => {
  const isAuthenticated = localStorage.getItem('token')
  
  // Check if route requires authentication
  if (to.meta.requiresAuth && !isAuthenticated) {
    next('/login')
    return
  }
  
  // Check if route requires admin role
  if (to.meta.requiresAdmin && isAuthenticated) {
    try {
      const response = await checkRole()
      if (response.user.role !== 'admin') {
        // Redirect non-admin users to regular dashboard
        next('/dashboard')
        return
      }
    } catch (error) {
      console.error('Role check failed:', error)
      // If role check fails, redirect to login
      localStorage.removeItem('token')
      localStorage.removeItem('user')
      next('/login')
      return
    }
  }
  
  // Special handling for dashboard route - redirect based on role
  if (to.path === '/dashboard' && isAuthenticated) {
    try {
      const response = await checkRole()
      if (response.user.role === 'admin') {
        // Redirect admin users to admin dashboard
        next('/admin')
        return
      }
    } catch (error) {
      console.error('Role check failed:', error)
      // Continue to regular dashboard if role check fails
    }
  }
  
  next()
})

export default router
